sub sanitize_redirect {
    my ($url) = @_;
    
    return '/' unless defined $url && $url ne '';
    
    $url =~ s/^\s+|\s+$//g;
    
    if ($url =~ m{^https?://}i) {
        my $server_name = $ENV{SERVER_NAME} || $ENV{HTTP_HOST} || '';
        $server_name =~ s/:\d+$//;
        
        unless ($url =~ m{^https?://\Q$server_name\E(?::\d+)?/}i) {
            return '/';
        }
    }
    
    unless ($url =~ m{^/}) {
        $url = '/' . $url;
    }
    
    $url =~ s/[\r\n]//g;
    
    return $url;
}